# Extended shapes module with concrete implementations

from shapes_types import IDrawable, IMeasurable, Shape, Point
from geometry_utils import ShapeType

class Circle(Shape, IDrawable, IMeasurable):
    center: Point
    radius: float

    def __init__(self, id: int, center: Point, radius: float):
        super().__init__(id, "Circle")
        self.center = center
        self.radius = radius

    def get_type(self) -> str:
        return "Circle"

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def draw(self) -> str:
        return f"Circle at ({self.center.x}, {self.center.y}) r={self.radius}"

class Rectangle(Shape, IDrawable, IMeasurable):
    top_left: Point
    width: float
    height: float

    def __init__(self, id: int, top_left: Point, width: float, height: float):
        super().__init__(id, "Rectangle")
        self.top_left = top_left
        self.width = width
        self.height = height

    def get_type(self) -> str:
        return "Rectangle"

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def draw(self) -> str:
        return f"Rectangle at ({self.top_left.x}, {self.top_left.y}) size={self.width}x{self.height}"
